"use strict";(globalThis.webpackChunkcybersec_kb=globalThis.webpackChunkcybersec_kb||[]).push([[4018],{1744(e){e.exports=JSON.parse('{"tag":{"label":"recon","permalink":"/docs/tags/recon","allTagsPath":"/docs/tags","count":11,"items":[{"id":"theory/git-exposure","title":".git Exposure \u2014 Source Code Leaks","description":"An exposed .git/ directory on a web server lets attackers reconstruct the entire source code of an application \u2014 including secrets and API keys from the full commit history.","permalink":"/docs/theory/git-exposure"},{"id":"tools/burp-suite","title":"Burp Suite","description":"One-liner: HTTP/HTTPS proxy that intercepts, modifies, and replays web requests between your browser and a server.","permalink":"/docs/tools/burp-suite"},{"id":"theory/burp-suite","title":"Burp Suite \u2014 HTTP Interception","description":"Burp Suite is a man-in-the-middle proxy that intercepts and manipulates HTTP/S traffic between your browser and a server, making it the go-to tool for web application security testing.","permalink":"/docs/theory/burp-suite"},{"id":"theory/dns-security","title":"DNS \u2014 Domain Squatting & Certificate Transparency","description":"Attackers register lookalike domains to impersonate your brand, and Certificate Transparency logs expose subdomains you may not realise are public \u2014 both are critical to monitor.","permalink":"/docs/theory/dns-security"},{"id":"tools/dnstwist","title":"dnstwist","description":"One-liner: Generates domain permutations (typosquatting variants) and checks whether they are registered.","permalink":"/docs/tools/dnstwist"},{"id":"theory/endpoints","title":"Endpoint Discovery","description":"Endpoint discovery is the practice of finding hidden API endpoints and admin panels by guessing URL patterns \u2014 and it matters because exposed hidden paths can give attackers direct access to sensitive functionality.","permalink":"/docs/theory/endpoints"},{"id":"tools/git-dumper","title":"git-dumper","description":"One-liner: Downloads an exposed .git repository from a web server so you can inspect its full history and contents.","permalink":"/docs/tools/git-dumper"},{"id":"tools/gobuster-dirbuster","title":"Gobuster / DirBuster","description":"One-liner: Brute-force directories and files on web servers using wordlists to discover hidden content.","permalink":"/docs/tools/gobuster-dirbuster"},{"id":"theory/iot-zero-day","title":"IoT, Smart Devices & Zero-day","description":"IoT devices expand the attack surface with outdated firmware and default credentials, making zero-day vulnerabilities especially dangerous since these devices are rarely patched.","permalink":"/docs/theory/iot-zero-day"},{"id":"tools/nikto","title":"Nikto","description":"One-liner: Web server vulnerability scanner that finds misconfigurations, default files, outdated software, and dangerous HTTP headers.","permalink":"/docs/tools/nikto"},{"id":"theory/recon","title":"Reconnaissance","description":"Reconnaissance is the process of gathering information about a target before attacking \u2014 the more you know, the easier the attack.","permalink":"/docs/theory/recon"}],"unlisted":false}}')}}]);